import { readFileSync } from 'node:fs';
import { resolve } from 'node:path';

import { describe, expect, it } from 'vitest';

const serverSource = readFileSync(
  resolve(__dirname, '../src/bin/openai-server.ts'),
  'utf8',
);
const agenticSource = readFileSync(
  resolve(__dirname, '../src/agentic-chat.ts'),
  'utf8',
);

describe('openai-server Thoth place-sense config', () => {
  it('builds the sim host from THOTH_PLACE_* env and threads it into the runtime', () => {
    expect(serverSource).toContain("process.env['THOTH_PLACE_TOOLS']");
    expect(serverSource).toContain("process.env['THOTH_PLACE_KNOT_PATH']");
    expect(serverSource).toContain("process.env['THOTH_PLACE_KNOT_BASE']");
    expect(serverSource).toContain("process.env['THOTH_PLACE_POI_BASE']");
    expect(serverSource).toContain("process.env['THOTH_PLACE_CACHE_CITIES']");
    expect(serverSource).toContain("process.env['THOTH_PLACE_MAX_AGENTS']");
    expect(serverSource).toContain('createThothPlaceSimHost');
    expect(serverSource).toContain('thothPlaceSimHost: THOTH_PLACE_SIM_HOST');
  });

  it('derives the place observer from thoth_observer and enables the tools', () => {
    expect(serverSource).toContain('thothPlaceObserver');
    expect(serverSource).toContain('{ thothPlaceTools: true }');
  });

  it('agentic loop composes the place client and gates the slim pointer on tool visibility', () => {
    expect(agenticSource).toContain('createThothPlaceMcpClient');
    expect(agenticSource).toContain('thothPlaceSimHost');
    expect(agenticSource).toContain('renderThothPlacePointerPromptContext');
    // The stuffed fallback must survive when tools are invisible to the model.
    expect(agenticSource).toContain('maxToolsInPrompt !== 0');
  });
});
